import{_ as e,c as l,o as i,ag as r}from"./chunks/framework.DPDPlp3K.js";const u=JSON.parse('{"title":"隐私权政策","description":"","frontmatter":{"aside":false,"search":false},"headers":[],"relativePath":"privacy-policy.md","filePath":"privacy-policy.md","lastUpdated":1746804817000}'),t={name:"privacy-policy.md"};function o(h,a,c,n,p,d){return i(),l("div",null,a[0]||(a[0]=[r('<h1 id="隐私权政策" tabindex="-1">隐私权政策 <a class="header-anchor" href="#隐私权政策" aria-label="Permalink to &quot;隐私权政策&quot;">​</a></h1><p>生效日期：2025 年 5 月 9 日</p><p>本隐私权政策说明“<a href="/">一个朋友</a>”网站（以下简称“本网站”）如何收集、使用和披露您的个人信息。该政策适用于通过本网站收集的所有信息。如对本隐私权政策有疑问，请<a href="/contact.html">联系我们</a>。</p><h2 id="一、信息收集" tabindex="-1">一、信息收集 <a class="header-anchor" href="#一、信息收集" aria-label="Permalink to &quot;一、信息收集&quot;">​</a></h2><p>我们可能收集以下个人信息：</p><ul><li>IP 地址</li><li>浏览器类型</li><li>操作系统</li><li>引荐网站</li><li>浏览页面</li><li>访问时间及其他使用情况</li></ul><h2 id="二、追踪与分析" tabindex="-1">二、追踪与分析 <a class="header-anchor" href="#二、追踪与分析" aria-label="Permalink to &quot;二、追踪与分析&quot;">​</a></h2><p>我们使用 Google Analytics 及其他分析工具，收集您的 IP 地址、设备信息及网站活动数据，以帮助我们了解用户使用情况并改进服务。</p><h2 id="三、广告" tabindex="-1">三、广告 <a class="header-anchor" href="#三、广告" aria-label="Permalink to &quot;三、广告&quot;">​</a></h2><p>本网站可能展示第三方广告。第三方广告网络可能使用 Cookie 及其他追踪技术收集您的信息，以展示相关广告。本隐私权政策不涵盖第三方广告商的行为。</p><h2 id="四、不销售产品或服务" tabindex="-1">四、不销售产品或服务 <a class="header-anchor" href="#四、不销售产品或服务" aria-label="Permalink to &quot;四、不销售产品或服务&quot;">​</a></h2><p>本网站不销售任何产品或服务，且不支持用户进行支付。</p><h2 id="五、不使用再营销服务" tabindex="-1">五、不使用再营销服务 <a class="header-anchor" href="#五、不使用再营销服务" aria-label="Permalink to &quot;五、不使用再营销服务&quot;">​</a></h2><p>我们当前不使用任何再营销服务进行广告宣传。</p><h2 id="六、加州消费者隐私法案-ccpa-及加州隐私权法案-cpra-权利" tabindex="-1">六、加州消费者隐私法案（CCPA）及加州隐私权法案（CPRA）权利 <a class="header-anchor" href="#六、加州消费者隐私法案-ccpa-及加州隐私权法案-cpra-权利" aria-label="Permalink to &quot;六、加州消费者隐私法案（CCPA）及加州隐私权法案（CPRA）权利&quot;">​</a></h2><p>加州居民享有以下权利：</p><ul><li>了解我们收集的个人信息类别、来源、目的及共享对象。</li><li>在特定情况下，要求删除个人信息。</li><li>虽然我们不出售个人信息，您仍可指示我们未来不出售您的信息。</li><li>行使权利时不受歧视。</li></ul><h2 id="七、通用数据保护条例-gdpr-权利" tabindex="-1">七、通用数据保护条例（GDPR）权利 <a class="header-anchor" href="#七、通用数据保护条例-gdpr-权利" aria-label="Permalink to &quot;七、通用数据保护条例（GDPR）权利&quot;">​</a></h2><p>欧洲经济区用户享有：</p><ul><li>访问、更正、删除个人信息的权利。</li><li>限制处理、数据可移植、反对处理及撤回同意权。</li><li>向监管机构投诉的权利。</li></ul><h2 id="八、儿童隐私" tabindex="-1">八、儿童隐私 <a class="header-anchor" href="#八、儿童隐私" aria-label="Permalink to &quot;八、儿童隐私&quot;">​</a></h2><p>本网站不面向13岁以下儿童，也不会故意收集其个人信息。如发现收集，将及时删除。</p><h2 id="九、隐私权政策变更" tabindex="-1">九、隐私权政策变更 <a class="header-anchor" href="#九、隐私权政策变更" aria-label="Permalink to &quot;九、隐私权政策变更&quot;">​</a></h2><p>本政策可能不定期更新，更新后立即生效。请定期查阅以了解最新内容。</p>',24)]))}const P=e(t,[["render",o]]);export{u as __pageData,P as default};
